function recordAudit(action, metadata = {}, req = {}) {
  const event = { id:id('audit'), action, tenantId:req.context?.tenantId || 'practice_demo', actorId:req.context?.actorId || 'demo_user', requestId:req.context?.requestId || id('req'), metadata, createdAt:new Date().toISOString() };
  auditEvents.unshift(event);
  return event;
}
function monthlyPay(employee) {
  const input = payrollInputs[employee.id] || {};
  const hourlyTotal = round((input.hourlyRates || []).reduce((sum, row) => sum + Number(row.rate || 0) * Number(row.hours || 0), 0));
  const additions = round((input.additions || []).reduce((sum, row) => sum + Number(row.amount || 0), 0));
  const statutory = input.statutory || {};
  const statutoryTotal = round(Number(statutory.sspAmount || 0) + Number(statutory.smpAmount || 0) + Number(statutory.sppAmount || 0));
  const gross = round(Number(input.basicPay ?? (Number(employee.annualSalary || 0) / 12)) + hourlyTotal + additions + statutoryTotal);
  const taxFree = round(12579.12 / 12);
  const taxable = Math.max(0, gross - taxFree);
  const incomeTax = round(taxable * 0.2);
  const niAdjustments = input.niAdjustments || {};
  const employeeNic = round(Math.max(0, gross - 1048) * 0.08 + Number(niAdjustments.employee || 0));
  const employerNic = round(Math.max(0, gross - 758) * 0.138 + Number(niAdjustments.employer || 0));
  const pension = input.pension || {};
  const employeePension = round(Number(pension.employeeFixed || 0) + gross * Number(pension.employeePercent ?? employee.pensionPercent ?? 0) / 100);
  const employerPension = round(Number(pension.employerFixed || 0) + gross * Number(pension.employerPercent ?? 3) / 100);
  const deductions = round((input.deductions || []).reduce((sum, row) => sum + Number(row.amount || 0), 0));
  const netPay = round(gross - incomeTax - employeeNic - employeePension - deductions);
  return { gross, taxFree, taxable, incomeTax, employeeNic, employerNic, employeePension, employerPension, deductions, hourlyTotal, additions, statutoryTotal, netPay };
}
function payrollPreview(employee) { return { employeeId:employee.id, name:`${employee.firstName} ${employee.lastName}`, ...monthlyPay(employee) }; }
function payRows(employee) { const p = monthlyPay(employee); return periods.map((period, idx) => ({ period, taxCode: idx >= 10 ? `${employee.taxCode} w1m1` : employee.taxCode, niLetter:employee.niLetter || 'A', totalPay:p.gross, additions:0, deductions:p.employeePension, incomeTax:p.incomeTax, employeeNic:p.employeeNic, netPay:p.netPay, employerNic:p.employerNic, rate1:employee.hourlyRate || '', hours1:employee.hourlyRate ? employerDetails.hoursPerWeek : '' })); }
function validatePayrollEmployee(employee = {}) {
  const errors = [];
  const warnings = [];
  if (!employee.worksNumber) errors.push('Works number / payroll ID is required.');
  if (!employee.firstName) errors.push('First name is required.');
  if (!employee.lastName) errors.push('Last name is required.');
  if (!employee.startDate) errors.push('Start date is required.');
  if (!employee.taxCode) errors.push('Tax code is required before a payroll run.');
  if (!employee.niLetter) errors.push('NI category letter is required before a payroll run.');
  if (employee.niNumber && !/^[A-Z]{2}[0-9]{6}[A-D]$/i.test(employee.niNumber)) warnings.push('NI number format should be checked before RTI submission.');
  if (!employee.starterStatement) warnings.push('Starter declaration A/B/C is missing.');
  if (!employee.dateOfBirth) warnings.push('Date of birth is needed for pension assessment and some statutory checks.');
  if (!employee.bankAccountNumber || !employee.bankSortCode) warnings.push('BACS bank details are incomplete.');
  return { employeeId:employee.id, valid:errors.length===0, errors, warnings, readiness:errors.length?'blocked':'payroll_ready_subject_to_warnings' };
}
function pensionAssessment(employee = {}) {
  const p = monthlyPay(employee);
  const annualised = round(p.gross * 12);
  const status = annualised >= 10000 ? 'eligible_jobholder' : annualised >= 6240 ? 'non_eligible_jobholder' : 'entitled_worker';
  return { employeeId:employee.id, annualisedQualifyingEarnings:annualised, assessmentStatus:status, provider:employers.find(e=>e.id===employee.employerId)?.pensionProvider || 'NEST', employeeContribution:p.employeePension, employerContribution:p.employerPension, exportStatus:'papdis_file_contract_ready' };
}
function p32Summary(employerId, period='Mar-2026') {
  const lines = employees.filter(e=>e.employerId===employerId && e.status==='active').map(payrollPreview);
  const totals = lines.reduce((a,p)=>({ paye:round(a.paye+p.incomeTax), employeeNic:round(a.employeeNic+p.employeeNic), employerNic:round(a.employerNic+p.employerNic), studentLoan:round(a.studentLoan+0), cisDeductionsSuffered:round(a.cisDeductionsSuffered+0), statutoryRecovery:round(a.statutoryRecovery+0), apprenticeshipLevy:round(a.apprenticeshipLevy+0) }), {paye:0,employeeNic:0,employerNic:0,studentLoan:0,cisDeductionsSuffered:0,statutoryRecovery:0,apprenticeshipLevy:0});
  const grossDue = round(totals.paye + totals.employeeNic + totals.employerNic + totals.studentLoan + totals.apprenticeshipLevy - totals.statutoryRecovery - totals.cisDeductionsSuffered);
  return { employerId, period, totals, grossDueToHmrc:grossDue, paymentReference:employerDetails.accountsOfficeReference, status:'calculation_preview_not_hmrc_submission' };
}
function rtiReadiness(employerId) {
  const employer = employers.find(e=>e.id===employerId);
  const employeeChecks = employees.filter(e=>e.employerId===employerId).map(validatePayrollEmployee);
  const blocking = [];
  if (!employer) blocking.push('Employer not found.');
  if (!employerDetails.payeReferenceDistrict || !employerDetails.payeReferenceSuffix) blocking.push('PAYE reference is incomplete.');
  if (!employerDetails.accountsOfficeReference) blocking.push('Accounts office reference is required.');
  if (!process.env.HMRC_CLIENT_ID || !process.env.HMRC_CLIENT_SECRET) blocking.push('HMRC OAuth credentials are not configured.');
  if (!process.env.HMRC_RTI_CERTIFIED_PRODUCT_ID) blocking.push('RTI product certification evidence is not configured.');
  return { employerId, status:blocking.length?'gated':'ready_for_certified_submission_path', blocking, employeeChecks, liveFilingEnabled:false, certificationNotice:'This product must not file live RTI until HMRC recognition/certification and credentials are complete.' };
}
function payRunEmployee(employee, template='standard') {
  const input = payrollInputs[employee.id] || {};
  const p = monthlyPay(employee);
  const earnings = [
    { code:'BASIC', description:'Basic Pay', amount:round(Number(input.basicPay ?? Number(employee.annualSalary || 0) / 12)) },
    ...(input.hourlyRates || []).filter(r=>Number(r.rate||0)||Number(r.hours||0)).map(r=>({ code:'HOURS', description:r.label, rate:Number(r.rate||0), hours:Number(r.hours||0), amount:round(Number(r.rate||0)*Number(r.hours||0)) })),
    ...(input.additions || []).filter(r=>Number(r.amount||0)).map(r=>({ code:r.code, description:r.description, amount:round(r.amount) })),
    ...(['sspAmount','smpAmount','sppAmount'].map(k=>({k, amount:Number((input.statutory||{})[k]||0)})).filter(x=>x.amount).map(x=>({ code:x.k.replace('Amount','').toUpperCase(), description:x.k.replace('Amount',''), amount:round(x.amount) })))
  ];
  const deductions = [
    { code:'PAYE', description:'Income Tax', amount:p.incomeTax },
    { code:'NIC', description:'Employee National Insurance', amount:p.employeeNic },
    { code:'PEN-EE', description:'Employee pension', amount:p.employeePension },
    ...(input.deductions || []).filter(r=>Number(r.amount||0)).map(r=>({ code:r.code, description:r.description, amount:round(r.amount) }))
  ];
  return { employee, input, period:input.period || 'Mar-2026', template, earnings, deductions, employerCosts:[{code:'NIC-ER',description:'Employer National Insurance',amount:p.employerNic},{code:'PEN-ER',description:'Employer pension',amount:p.employerPension}], totals:{ gross:p.gross, taxable:p.taxable, additions:p.additions, hourly:p.hourlyTotal, statutory:p.statutoryTotal, totalDeductions:round(deductions.reduce((s,d)=>s+d.amount,0)), employerCost:round(p.employerNic+p.employerPension), netPay:p.netPay }, ytd:{ gross:round(p.gross*12), paye:round(p.incomeTax*12), employeeNic:round(p.employeeNic*12), employeePension:round(p.employeePension*12), netPay:round(p.netPay*12) }, status:'draft_calculation_preview' };
}
function validateJournal(body = {}) {
  const lines = Array.isArray(body.lines) ? body.lines : [];
  const errors = [];
  if (!body.description) errors.push('Journal description is required.');
  if (lines.length < 2) errors.push('A journal must contain at least two lines.');
  lines.forEach((line, i) => {
    const debit = Number(line.debit || 0), credit = Number(line.credit || 0);
    if (!line.accountCode) errors.push(`Line ${i + 1}: account code is required.`);
    if (debit > 0 && credit > 0) errors.push(`Line ${i + 1}: use either debit or credit, not both.`);
    if (debit === 0 && credit === 0) errors.push(`Line ${i + 1}: debit or credit amount is required.`);
  });
  const debitTotal = round(lines.reduce((sum, line) => sum + Number(line.debit || 0), 0));
  const creditTotal = round(lines.reduce((sum, line) => sum + Number(line.credit || 0), 0));
  const difference = round(debitTotal - creditTotal);
  if (difference !== 0) errors.push('Total debits must equal total credits before posting.');
  return { valid:errors.length === 0, debitTotal, creditTotal, difference, errors, postingPolicy:errors.length ? 'blocked_until_valid_and_balanced' : 'postable' };
}
function normal(account) { return ['asset','expense'].includes(account.accountType) ? round(Number(account.debit || 0) - Number(account.credit || 0)) : round(Number(account.credit || 0) - Number(account.debit || 0)); }
function section(accounts, prefix, type) { const lines = accounts.filter(a => a.accountType === type && String(a.reportSection || '').startsWith(prefix)).map(a => ({...a, amount:normal(a)})); return { section:prefix, lines, total:round(lines.reduce((sum, line) => sum + line.amount, 0)) }; }

