const $=id=>document.getElementById(id), fmt=n=>'GBP '+Number(n||0).toLocaleString('en-GB',{maximumFractionDigits:0});let S={clients:[],employers:[],employees:[],docs:[],coa:[],details:{},payRows:[],providers:[]};
