const detailNames=['Employer','Tax office','Bank','Terms','Class 1A NIC','Auto-enrolment'];const payNames=['Basic','Hourly','Additions','Deductions','Pensions','Attachments','SSP & SMP','Holiday Pay','Adjustments','Rounding','Loans','Notes','Tax & NIC'];
function go(p){document.querySelectorAll('.page').forEach(x=>x.classList.remove('active'));$(p).classList.add('active');document.querySelectorAll('nav a').forEach(a=>a.classList.toggle('active',a.dataset.p===p));eyebrow.textContent=pages[p][0];title.textContent=pages[p][1]}
nav.onclick=e=>{if(e.target.dataset.p)go(e.target.dataset.p)};async function api(p,o={}){const r=await fetch(p,{headers:{'content-type':'application/json'},...o});const t=await r.text();let d;try{d=JSON.parse(t)}catch{d=t}if(!r.ok)throw d;return d}const fd=f=>Object.fromEntries(new FormData(f).entries());const card=(a,b,c='')=>'<div class="card"><strong>'+a+'</strong><span>'+b+'</span><small>'+c+'</small></div>';const label=k=>k.replace(/([A-Z])/g,' $1').replace(/^./,s=>s.toUpperCase());const val=k=>(S.details[k]??'');const inp=(k,t='text')=>'<label>'+label(k)+'<input data-k="'+k+'" type="'+t+'" value="'+val(k)+'"></label>';const txt=k=>'<label>'+label(k)+'<textarea data-k="'+k+'">'+val(k)+'</textarea></label>';const chk=(k,copy)=>'<label class="check"><input data-k="'+k+'" type="checkbox" '+(S.details[k]?'checked':'')+'> '+copy+'</label>';
function detailHtml(tab){if(tab==='Employer')return '<div class="fields">'+inp('name')+txt('address')+inp('postcode')+inp('telephone')+inp('email')+inp('contactForename')+inp('contactSurname')+inp('pdfPassword','password')+inp('userReference')+inp('payeStarted','date')+inp('payeCeased','date')+chk('rtiBatch','RTI batch processing')+chk('uniqueWorksNumber','Require unique works number / payroll ID')+chk('warnMinimumWage','Warn below National Minimum Wage')+chk('showAgeOnHourly','Show age on hourly pay tab')+'</div>';if(tab==='Tax office')return '<div class="fields">'+inp('payeReferenceDistrict')+inp('payeReferenceSuffix')+inp('accountsOfficeReference')+inp('paymentMethod')+inp('uniqueTaxReference')+inp('corporationTaxReference')+inp('payrollGivingReference')+inp('childSupportReference')+inp('payeDistrict')+txt('taxOfficeAddress')+inp('taxOfficePostcode')+inp('taxOfficeTelephone')+inp('apprenticeshipLevyAllowance','number')+chk('serThisYear','SER qualified this year')+chk('serLastYear','SER qualified last year')+chk('noRtiDueWarnings','No RTI due warnings')+chk('claimNicAllowance','Claim employment/NIC allowance')+chk('forceYearEndAmendmentEps','Force all employees on Year End Amendment EPS')+'</div>';if(tab==='Bank')return '<div class="fields">'+inp('accountName')+inp('accountNumber')+inp('paymentReference')+inp('bankName')+inp('sortCode')+txt('bankAddress')+inp('bankPostcode')+inp('bankTelephone')+inp('paymentLeadDays','number')+chk('includeBankInRti','Include these details in RTI returns')+'</div>';if(tab==='Terms')return '<div class="fields">'+inp('hoursPerWeek','number')+chk('paidOvertime','Paid overtime')+inp('weeksNoticeRequired','number')+inp('daysSicknessFullPay','number')+inp('maleRetirementAge','number')+inp('femaleRetirementAge','number')+chk('mayJoinPension','May join pension scheme')+inp('holidayDays','number')+inp('maxCarryOverDays','number')+'</div>';if(tab==='Class 1A NIC')return '<div class="fields">'+inp('benefitsSubjectToClass1a','number')+txt('class1aAdjustmentNote')+chk('p11dSubmissionRequired','P11D submission required')+'</div><div class="subgrid">'+['P11D expenses & benefits','Class 1A NIC summary','PBIK summary'].map(x=>card(x,'Ready to generate from payroll file','Year-end')).join('')+'</div>';return '<div class="fields">'+inp('stagingDate','date')+inp('reEnrolmentDate','date')+inp('deferUntil','date')+inp('pensionUsername')+inp('pensionPassword','password')+chk('samePensionCredentials','Use same credentials in all data files')+chk('reportTaxMonthly','Report as Tax Monthly')+chk('reportTaxWeekly','Report as Tax Weekly')+chk('askPaymentDueDate','Ask for payment due date')+inp('monthlyEarningsPeriod','number')+inp('weeklyEarningsAdjustment','number')+'</div><div class="subgrid">'+(S.providers||[]).map(p=>card(p,'Setup guide','Pension provider')).join('')+'</div>'}
