function renderPay(tab='Basic'){payTabs.innerHTML=payNames.map(t=>'<button class="tab '+(t===tab?'active':'')+'" data-pay="'+t+'">'+t+'</button>').join('');const cols=tab==='Hourly'?['period','rate1','hours1']:['period','taxCode','niLetter','totalPay','additions','deductions','incomeTax','employeeNic','netPay','employerNic'];payGrid.innerHTML='<table class="pay-grid"><tr>'+cols.map(c=>'<th>'+c+'</th>').join('')+'</tr>'+S.payRows.map(r=>'<tr>'+cols.map(c=>'<td>'+((r[c]??'')||'')+'</td>').join('')+'</tr>').join('')+'</table>';payTabs.onclick=e=>{if(e.target.dataset.pay)renderPay(e.target.dataset.pay)}}
function renderTax(){const r=S.payRows[S.payRows.length-1]||{};taxCalc.innerHTML='<table><tr><th>Calculation line</th><th>Amount</th><th>Ref</th></tr>'+[['Basic pay',r.totalPay,'a'],['Total allowable deductions',0,'b'],['Taxable pay for current period',r.totalPay,'c = a-b'],['Tax code for current period',r.taxCode,''],['Tax-free pay for the period',1048.26,'i'],['Net taxable pay',Math.max(0,(r.totalPay||0)-1048.26),'j'],['Tax due for current period',r.incomeTax,''],['Employee NIC',r.employeeNic,''],['Employer NIC',r.employerNic,''],['Net pay',r.netPay,'']].map(x=>'<tr><td>'+x[0]+'</td><td>'+x[1]+'</td><td>'+x[2]+'</td></tr>').join('')+'</table>'}
async function loadEmployerDetails(){S.details=await api('/api/payroll/employers/emp_klop/details');renderDetails()}async function loadPay(){const e=payEmployee.value||'ee_shaan';const r=await api('/api/payroll/employees/'+e+'/pay-details');S.payRows=r.rows;renderPay();renderTax()}async function refreshFoundation(){foundationOut.textContent=JSON.stringify(await api('/api/platform/foundation'),null,2)}async function refreshPersistence(){const p=await api('/api/platform/persistence-status');persistenceOut.textContent=JSON.stringify(p,null,2);kpersist.textContent=p.mode;kdb.textContent=p.environment.databaseUrlConfigured?'Set':'Missing'}async function refreshRunbook(){const r=await api('/api/platform/migration-runbook');runbookOut.textContent=JSON.stringify(r,null,2);kseed.textContent=(await api('/api/platform/seed-blueprint')).chartOfAccountsCount}async function refreshAudit(){const a=await api('/api/audit-events');auditOut.textContent=JSON.stringify(a,null,2);kaudit.textContent=a.length}
